package com.interview.lld.ratelimiter.model;

// ── WHY THIS CLASS ──────────────────────────────────────────────────────────
// Base exception for all rate-limiter errors. Every specific error extends this,
// so caller code can catch one type instead of many, or catch specific ones if needed.
// 🎙️ "Single base exception for the domain — makes error handling clean and uniform."
public class RateLimiterException extends RuntimeException {
    public RateLimiterException(String message) {
        super(message);
    }
}

package com.interview.lld.ratelimiter.model;

// Thrown when a customer's request is denied because they've exceeded their rate limit.
public class RateLimitExceededException extends RateLimiterException {
    public RateLimitExceededException(String customerId) {
        super("Rate limit exceeded for customer: " + customerId);
    }
}

package com.interview.lld.ratelimiter.gateway;

// ── WHY THIS CLASS ──────────────────────────────────────────────────────────
// Injectable clock interface for testability. In production, returns System.currentTimeMillis().
// In tests, returns a controlled value so we can "fast-forward time" without actually waiting.
// 🎙️ "Clock injection lets tests move time forward instantly — no Thread.sleep needed."
public interface Clock {
    long nowMillis();
}

package com.interview.lld.ratelimiter.gateway;

// Production implementation: returns the actual system time in milliseconds since epoch.
public class SystemClock implements Clock {
    @Override
    public long nowMillis() {
        return System.currentTimeMillis();
    }
}

package com.interview.lld.ratelimiter.strategy;

// ── WHY THIS INTERFACE ──────────────────────────────────────────────────────
// Strategy seam for different rate-limiting algorithms. The service delegates
// to this interface, never knowing if it's token-bucket, sliding-window, or
// something else. Adding a new algorithm = one new class, zero core changes.
// 🎙️ "The orchestrator depends on the abstraction, not the concrete algorithm."
public interface RateLimitStrategy {
    /**
     * Attempts to allow a request for the given customer at the given timestamp.
     * @param customerId the customer making the request
     * @param timestampMillis current time in milliseconds
     * @return true if allowed, false if rate limit exceeded
     */
    boolean allow(String customerId, long timestampMillis);

    /**
     * Resets the state for a specific customer (for testing/admin purposes).
     */
    void reset(String customerId);
}

package com.interview.lld.ratelimiter.strategy;

import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.locks.ReentrantLock;

// ── WHY THIS CLASS ──────────────────────────────────────────────────────────
// Token bucket algorithm: each customer has a bucket with capacity tokens that
// refill at a fixed rate. Each request consumes one token. If no tokens available,
// request is denied. Thread-safe with per-customer lock striping — different customers
// never contend with each other.
// 🎙️ "Token bucket with per-customer locks — requests to different customers run in parallel."
public class TokenBucketStrategy implements RateLimitStrategy {
    private final int capacity;          // max tokens a bucket can hold
    private final double refillRate;     // tokens added per millisecond

    // Per-customer state: mutable, guarded by per-customer lock
    private static class BucketState {
        double tokens;               // current token count (can be fractional during refill)
        long lastRefillTimeMillis;   // last time we refilled tokens
        final ReentrantLock lock = new ReentrantLock();  // guards tokens + lastRefillTimeMillis
    }

    private final ConcurrentHashMap<String, BucketState> buckets = new ConcurrentHashMap<>();

    /**
     * @param capacity max tokens per bucket
     * @param refillRatePerSecond tokens added per second (converted internally to per-millisecond)
     */
    public TokenBucketStrategy(int capacity, double refillRatePerSecond) {
        if (capacity <= 0) throw new IllegalArgumentException("capacity must be positive");
        if (refillRatePerSecond <= 0) throw new IllegalArgumentException("refillRate must be positive");
        this.capacity = capacity;
        this.refillRate = refillRatePerSecond / 1000.0;  // convert to per-millisecond
    }

    @Override
    public boolean allow(String customerId, long timestampMillis) {
        // WHY: computeIfAbsent is atomic — only one thread creates the BucketState for a new customer.
        //      This avoids the "two threads both see absent, both create, one's object is lost" race.
        BucketState state = buckets.computeIfAbsent(customerId, k -> {
            BucketState newState = new BucketState();
            newState.tokens = capacity;  // start with full bucket
            newState.lastRefillTimeMillis = timestampMillis;
            return newState;
        });

        // WHY: Per-customer lock. Thread A checking customer X and thread B checking customer Y
        //      never block each other — they lock different BucketState objects. This is lock
        //      striping at the customer-id level.
        state.lock.lock();
        try {
            // WHY: Refill tokens based on time elapsed since last refill.
            //      If 1000ms passed and refillRate is 10 tokens/sec, add 10 tokens (capped at capacity).
            long elapsed = timestampMillis - state.lastRefillTimeMillis;
            if (elapsed > 0) {
                double tokensToAdd = elapsed * refillRate;
                state.tokens = Math.min(capacity, state.tokens + tokensToAdd);
                state.lastRefillTimeMillis = timestampMillis;
            }

            // WHY: Check if at least one token available. If yes, consume it and allow the request.
            if (state.tokens >= 1.0) {
                state.tokens -= 1.0;
                return true;
            } else {
                return false;  // no tokens left — rate limit exceeded
            }
        } finally {
            state.lock.unlock();
        }
    }

    @Override
    public void reset(String customerId) {
        BucketState state = buckets.get(customerId);
        if (state != null) {
            state.lock.lock();
            try {
                state.tokens = capacity;
                state.lastRefillTimeMillis = System.currentTimeMillis();
            } finally {
                state.lock.unlock();
            }
        }
    }
}

package com.interview.lld.ratelimiter.strategy;

import java.util.LinkedList;
import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.locks.ReentrantLock;

// ── WHY THIS CLASS ──────────────────────────────────────────────────────────
// Sliding window algorithm: track timestamps of last N requests per customer.
// For each new request, drop old timestamps outside the window, then check count.
// If count < limit, allow and record the new timestamp. Thread-safe with per-customer locks.
// 🎙️ "Sliding window counts actual requests in the last N seconds — more precise than fixed windows."
public class SlidingWindowStrategy implements RateLimitStrategy {
    private final int limit;              // max requests per window
    private final long windowMillis;      // window duration in milliseconds

    // Per-customer state: list of recent request timestamps
    private static class WindowState {
        final LinkedList<Long> timestamps = new LinkedList<>();  // sorted by insertion (oldest first)
        final ReentrantLock lock = new ReentrantLock();          // guards timestamps list
    }

    private final ConcurrentHashMap<String, WindowState> windows = new ConcurrentHashMap<>();

    /**
     * @param limit max requests allowed in the window
     * @param windowSeconds window duration in seconds
     */
    public SlidingWindowStrategy(int limit, int windowSeconds) {
        if (limit <= 0) throw new IllegalArgumentException("limit must be positive");
        if (windowSeconds <= 0) throw new IllegalArgumentException("windowSeconds must be positive");
        this.limit = limit;
        this.windowMillis = windowSeconds * 1000L;
    }

    @Override
    public boolean allow(String customerId, long timestampMillis) {
        // WHY: Atomic creation of per-customer state if not present.
        WindowState state = windows.computeIfAbsent(customerId, k -> new WindowState());

        // WHY: Per-customer lock striping — different customers don't block each other.
        state.lock.lock();
        try {
            // WHY: Remove timestamps older than the window. The window is [now - windowMillis, now].
            //      Oldest timestamps are at the front of the LinkedList, so we poll from front.
            long windowStart = timestampMillis - windowMillis;
            while (!state.timestamps.isEmpty() && state.timestamps.peek() <= windowStart) {
                state.timestamps.poll();  // drop old timestamp
            }

            // WHY: After cleanup, check if we're under the limit. If yes, allow and record timestamp.
            if (state.timestamps.size() < limit) {
                state.timestamps.add(timestampMillis);  // append to end (newest)
                return true;
            } else {
                return false;  // limit reached
            }
        } finally {
            state.lock.unlock();
        }
    }

    @Override
    public void reset(String customerId) {
        WindowState state = windows.get(customerId);
        if (state != null) {
            state.lock.lock();
            try {
                state.timestamps.clear();
            } finally {
                state.lock.unlock();
            }
        }
    }
}

package com.interview.lld.ratelimiter.service;

import com.interview.lld.ratelimiter.gateway.Clock;
import com.interview.lld.ratelimiter.model.RateLimitExceededException;
import com.interview.lld.ratelimiter.strategy.RateLimitStrategy;

// ── WHY THIS CLASS ──────────────────────────────────────────────────────────
// The orchestrator: public API for rate limiting. Delegates algorithm logic to
// a pluggable strategy, injects a clock for testability. Clean single-threaded
// core — no locks here. Thread-safety is pushed down into the strategy implementations,
// which use per-customer lock striping so different customers never contend.
// 🎙️ "The service is the public API — it coordinates clock and strategy, but the
//      strategy owns the actual rate-limit logic."
public class RateLimiterService {
    private final RateLimitStrategy strategy;
    private final Clock clock;

    /**
     * @param strategy the rate-limiting algorithm (token bucket, sliding window, etc.)
     * @param clock injectable clock for testing (pass SystemClock for production)
     */
    public RateLimiterService(RateLimitStrategy strategy, Clock clock) {
        if (strategy == null) throw new IllegalArgumentException("strategy cannot be null");
        if (clock == null) throw new IllegalArgumentException("clock cannot be null");
        this.strategy = strategy;
        this.clock = clock;
    }

    /**
     * Attempts to allow a request for the given customer at the current time.
     * @param customerId the customer making the request
     * @return true if allowed
     * @throws RateLimitExceededException if rate limit exceeded
     */
    public boolean allow(String customerId) {
        if (customerId == null || customerId.isEmpty()) {
            throw new IllegalArgumentException("customerId cannot be null or empty");
        }

        long now = clock.nowMillis();
        boolean allowed = strategy.allow(customerId, now);

        if (!allowed) {
            throw new RateLimitExceededException(customerId);
        }

        return true;
    }

    /**
     * Attempts to allow a request for the given customer at an explicit timestamp.
     * Useful for testing or when you have a pre-captured timestamp.
     * @param customerId the customer making the request
     * @param timestampMillis explicit timestamp in milliseconds
     * @return true if allowed
     * @throws RateLimitExceededException if rate limit exceeded
     */
    public boolean allow(String customerId, long timestampMillis) {
        if (customerId == null || customerId.isEmpty()) {
            throw new IllegalArgumentException("customerId cannot be null or empty");
        }

        boolean allowed = strategy.allow(customerId, timestampMillis);

        if (!allowed) {
            throw new RateLimitExceededException(customerId);
        }

        return true;
    }

    /**
     * Resets rate limit state for a customer (for testing or admin purposes).
     */
    public void reset(String customerId) {
        if (customerId == null || customerId.isEmpty()) {
            throw new IllegalArgumentException("customerId cannot be null or empty");
        }
        strategy.reset(customerId);
    }
}

package com.interview.lld.ratelimiter;

import com.interview.lld.ratelimiter.gateway.Clock;
import com.interview.lld.ratelimiter.gateway.SystemClock;
import com.interview.lld.ratelimiter.model.RateLimitExceededException;
import com.interview.lld.ratelimiter.service.RateLimiterService;
import com.interview.lld.ratelimiter.strategy.SlidingWindowStrategy;
import com.interview.lld.ratelimiter.strategy.TokenBucketStrategy;

/**
 * Demo driver exercising rate limiter with both strategies.
 * Cases: happy path, boundary (exactly at limit), exceeded, time-based refill, concurrent customers.
 */
public class Main {
    public static void main(String[] args) {
        System.out.println("=== Rate Limiter Demo ===\n");

        demoTokenBucket();
        System.out.println();
        demoSlidingWindow();
        System.out.println();
        demoConcurrentCustomers();

        System.out.println("\n=== All cases passed ===");
    }

    private static void demoTokenBucket() {
        System.out.println("--- Token Bucket: 5 req/sec, capacity 5 ---");

        // Fake clock for controlled testing
        FakeClock clock = new FakeClock(1000000000L);
        TokenBucketStrategy strategy = new TokenBucketStrategy(5, 5.0);  // 5 tokens, 5/sec refill
        RateLimiterService limiter = new RateLimiterService(strategy, clock);

        // Case 1: Burst of 5 requests — all allowed (bucket starts full)
        for (int i = 1; i <= 5; i++) {
            limiter.allow("customer-A", clock.nowMillis());
            System.out.println("  Request " + i + " -> allowed");
        }

        // Case 2: 6th request immediately — denied (bucket empty)
        try {
            limiter.allow("customer-A", clock.nowMillis());
            throw new AssertionError("Expected RateLimitExceededException");
        } catch (RateLimitExceededException e) {
            System.out.println("  Request 6 -> denied (bucket empty)");
        }

        // Case 3: Advance time by 1 second (refills 5 tokens) — 5 more requests allowed
        clock.advance(1000);
        for (int i = 7; i <= 11; i++) {
            limiter.allow("customer-A", clock.nowMillis());
        }
        System.out.println("  After 1s: 5 more requests -> allowed");

        System.out.println("Token Bucket demo -> OK");
    }

    private static void demoSlidingWindow() {
        System.out.println("--- Sliding Window: 3 req / 2 seconds ---");

        FakeClock clock = new FakeClock(2000000000L);
        SlidingWindowStrategy strategy = new SlidingWindowStrategy(3, 2);  // 3 requests per 2 seconds
        RateLimiterService limiter = new RateLimiterService(strategy, clock);

        // Case 1: 3 requests at t=0 — all allowed
        for (int i = 1; i <= 3; i++) {
            limiter.allow("customer-B", clock.nowMillis());
            System.out.println("  Request " + i + " at t=0 -> allowed");
        }

        // Case 2: 4th request at t=0 — denied
        try {
            limiter.allow("customer-B", clock.nowMillis());
            throw new AssertionError("Expected RateLimitExceededException");
        } catch (RateLimitExceededException e) {
            System.out.println("  Request 4 at t=0 -> denied (limit reached)");
        }

        // Case 3: Advance 1 second (t=1s) — still have 3 requests in window [t-2s, t], so denied
        clock.advance(1000);
        try {
            limiter.allow("customer-B", clock.nowMillis());
            throw new AssertionError("Expected RateLimitExceededException");
        } catch (RateLimitExceededException e) {
            System.out.println("  Request at t=1s -> denied (old requests still in window)");
        }

        // Case 4: Advance to t=2.1s — oldest 3 requests now outside window, so 1 request allowed
        clock.advance(1100);
        limiter.allow("customer-B", clock.nowMillis());
        System.out.println("  Request at t=2.1s -> allowed (window slid past old requests)");

        System.out.println("Sliding Window demo -> OK");
    }

    private static void demoConcurrentCustomers() {
        System.out.println("--- Concurrent Customers (no cross-contention) ---");

        Clock clock = new SystemClock();
        TokenBucketStrategy strategy = new TokenBucketStrategy(10, 10.0);
        RateLimiterService limiter = new RateLimiterService(strategy, clock);

        // Different customers should not block each other — this is the lock-striping win
        for (int i = 1; i <= 5; i++) {
            limiter.allow("customer-X");
            limiter.allow("customer-Y");
            limiter.allow("customer-Z");
        }
        System.out.println("  15 requests across 3 customers -> all allowed (no contention)");

        System.out.println("Concurrent customers demo -> OK");
    }

    // Fake clock for testing: time is explicit and controllable
    private static class FakeClock implements Clock {
        private long currentMillis;

        public FakeClock(long startMillis) {
            this.currentMillis = startMillis;
        }

        @Override
        public long nowMillis() {
            return currentMillis;
        }

        public void advance(long deltaMillis) {
            this.currentMillis += deltaMillis;
        }
    }
}
